/**
 * `voice-evals init` — scaffold a voice-evals.config.ts in the cwd.
 *
 * Phase 6.x. The config file is the canonical entry point for the
 * non-CLI surface (programmatic Bun / Node consumers); shipping a
 * starter file lets users go from `npm install` to a working call in
 * one command.
 */

import {existsSync, writeFileSync} from 'node:fs';
import {join} from 'node:path';
import {createTracer} from '../../internal/jsonl-trace';

const TEMPLATE = `/**
 * voice-evals.config.ts — generated by \`voice-evals init\`.
 *
 * Wire your ElevenLabs API key and (optionally) an LLM callback for the
 * proposer / judges. Everything in this file is consumer-controlled —
 * the package does not parse it, you pass it to the relevant functions
 * yourself.
 */

import {
  createVoiceEvalsClient,
  type LlmCompleteCallback,
} from '@wranngle/voice-evals';

export const client = createVoiceEvalsClient({
  apiKey: process.env.ELEVENLABS_API_KEY ?? '',
});

/**
 * LLM callback for proposer / designer / judges. Implement against your
 * provider of choice (Anthropic SDK, OpenAI SDK, local Llama, etc.).
 * Keep temperature low for deterministic proposals.
 */
export const llm: LlmCompleteCallback = async ({system, user}) => {
  // Stub: returns empty array so the proposer/designer gracefully no-op
  // until you wire a real model. Replace with your provider call.
  void system;
  void user;
  return '[]';
};

export const config = {
  agentId: process.env.ELEVENLABS_AGENT_ID ?? '',
  baselinesDir: 'baselines',
};
`;

export type InitOptions = {
  cwd?: string;
  /** Force overwrite if the config file exists. Default false. */
  force?: boolean;
  /** Stream output here. Defaults to stdout. */
  out?: (line: string) => void;
};

export async function runInit(options: InitOptions = {}): Promise<number> {
  const trace = createTracer('cli.init');
  const cwd = options.cwd ?? process.cwd();
  const force = options.force ?? false;
  const out = options.out ?? ((line: string) => {
    process.stdout.write(`${line}\n`);
  });

  const target = join(cwd, 'voice-evals.config.ts');
  trace.info('init.start', {target, force});

  if (existsSync(target) && !force) {
    out(`voice-evals.config.ts already exists at ${target}. Use --force to overwrite.`);
    trace.warn('init.refused', {target, reason: 'exists_no_force'});
    return 1;
  }

  writeFileSync(target, TEMPLATE, 'utf8');
  out(`Wrote ${target}`);
  out('Edit ELEVENLABS_API_KEY in your .env and wire your LLM callback before calling polishLoop / proposeFix.');
  trace.info('init.complete', {target});
  return 0;
}
